### Private Hook: `useSidebarSlot`

Add this INSIDE `AppShell.tsx` (private, not exported):

```typescript
interface SidebarSlot {
  /** Stable key for AnimatePresence — triggers cross-fade on change */
  key: string;
  /** The sidebar body component to render */
  body: React.ReactNode;
}

function useSidebarSlot(): SidebarSlot {
  const pathname = useRouterState({ select: (s) => s.location.pathname });
  switch (pathname) {
    case '/':
      return { key: 'dashboard', body: <DashboardSidebar /> };
    default:
      return { key: 'session', body: <SessionSidebar /> };
  }
}
```

### Private Hook: `useHeaderSlot`

Add this INSIDE `AppShell.tsx` (private, not exported). This hook needs access to agent state, so it takes parameters or reads from the component's scope. Since it needs `currentAgent`, `agentVisual`, and `isStreaming`, the cleanest approach is to define it as a function that takes those values:

```typescript
interface HeaderSlot {
  key: string;
  content: React.ReactNode;
  borderStyle: React.CSSProperties | undefined;
}

function useHeaderSlot({
  currentAgent,
  agentVisual,
  isStreaming,
}: {
  currentAgent: AgentManifest | null | undefined;
  agentVisual: AgentVisual;
  isStreaming: boolean;
}): HeaderSlot {
  const pathname = useRouterState({ select: (s) => s.location.pathname });
  switch (pathname) {
    case '/':
      return {
        key: 'dashboard',
        content: <DashboardHeader />,
        borderStyle: undefined,
      };
    default:
      return {
        key: 'session',
        content: (
          <SessionHeader agent={currentAgent} visual={agentVisual} isStreaming={isStreaming} />
        ),
        borderStyle: currentAgent
          ? { borderBottomColor: `color-mix(in srgb, ${agentVisual.color} 25%, var(--border))` }
          : undefined,
      };
  }
}
```

Note: Import the types at the top of AppShell.tsx:
```typescript
