import { describe, it, expect, vi, beforeAll } from 'vitest';
import { render, screen, fireEvent } from '@testing-library/react';
import '@testing-library/jest-dom';
import { QueryClient, QueryClientProvider } from '@tanstack/react-query';
import { DashboardSidebar } from '../ui/DashboardSidebar';
import { SidebarProvider, TooltipProvider } from '@/layers/shared/ui';

// Mock TanStack Router
const mockNavigate = vi.fn();
vi.mock('@tanstack/react-router', () => ({
  useNavigate: () => mockNavigate,
}));

beforeAll(() => {
  Object.defineProperty(window, 'matchMedia', {
    writable: true,
    value: vi.fn().mockImplementation((query: string) => ({
      matches: false,
      media: query,
      onchange: null,
      addListener: vi.fn(),
      removeListener: vi.fn(),
      addEventListener: vi.fn(),
      removeEventListener: vi.fn(),
      dispatchEvent: vi.fn(),
    })),
  });
});

function renderWithProviders(ui: React.ReactElement) {
  const queryClient = new QueryClient({
    defaultOptions: { queries: { retry: false } },
  });
  return render(
    <QueryClientProvider client={queryClient}>
      <TooltipProvider>
        <SidebarProvider>{ui}</SidebarProvider>
      </TooltipProvider>
    </QueryClientProvider>
  );
}

describe('DashboardSidebar', () => {
  it('renders Dashboard nav item as active', () => {
    renderWithProviders(<DashboardSidebar />);
    const dashboardButton = screen.getByText('Dashboard');
    expect(dashboardButton).toBeInTheDocument();
    // isActive is set on the SidebarMenuButton — check data attribute
    expect(dashboardButton.closest('[data-active="true"]')).toBeInTheDocument();
  });

  it('renders Sessions nav item that navigates to /session', () => {
    renderWithProviders(<DashboardSidebar />);
    const sessionsButton = screen.getByText('Sessions');
    expect(sessionsButton).toBeInTheDocument();

    fireEvent.click(sessionsButton);
    expect(mockNavigate).toHaveBeenCalledWith({ to: '/session' });
  });

  it('shows placeholder content', () => {
    renderWithProviders(<DashboardSidebar />);
    expect(screen.getByText('Agent overview coming soon')).toBeInTheDocument();
  });

  it('does not render SidebarFooter (footer is in AppShell)', () => {
    renderWithProviders(<DashboardSidebar />);
    // DashboardSidebar should not render any footer-like content
    expect(screen.queryByLabelText('Settings')).not.toBeInTheDocument();
  });
});
```

Note: The `data-active` attribute check may need adjustment based on how `SidebarMenuButton` handles the `isActive` prop. If `isActive` sets `data-active="true"` on the rendered element, the test works as-is. If it uses a different mechanism (e.g., `aria-current` or a CSS class), adjust accordingly. Run the test and check the rendered output.

